import type { Connector } from "wagmi";
import { clearUnrememberedStoredAdminApiKey } from "@/utils/adminKeyAuth";
import {
  migrateUnprefixedStorageKeys,
  storageKey,
  walletStorageKey,
  resolveWalletAddress,
  setLastWalletAddress,
  clearLastWalletAddress,
} from "@/utils/storage";

const WALLET_STORAGE_SUFFIXES = [
  "orderlyProfile",
  "orderlyLoginContext",
  "orderlyWalletSignature",
  "orderlyDexId",
  "auth_token",
  "auth_user",
  "current_user_broker_id",
  "orderlyBuilderName",
  "orderlyFees",
  "orderlySwapFee",
  "orderlyFeeTier",
  "orderlyCustomFeeUsers",
];

const WALLET_DISCONNECT_GUARD_KEY = "orderly-one:wallet-disconnected";

export function markWalletIntentionallyDisconnected() {
  if (typeof window === "undefined") return;
  window.sessionStorage.setItem(WALLET_DISCONNECT_GUARD_KEY, "true");
}

export function clearWalletDisconnectGuard() {
  if (typeof window === "undefined") return;
  window.sessionStorage.removeItem(WALLET_DISCONNECT_GUARD_KEY);
}

export function isWalletIntentionallyDisconnected() {
  if (typeof window === "undefined") return false;
  return window.sessionStorage.getItem(WALLET_DISCONNECT_GUARD_KEY) === "true";
}

export function clearConnectionStorage(address?: string | null) {
  if (typeof window === "undefined") return;
  migrateUnprefixedStorageKeys();
  const wallet = resolveWalletAddress(address);
  for (const suffix of WALLET_STORAGE_SUFFIXES) {
    if (wallet) {
      window.localStorage.removeItem(walletStorageKey(suffix, wallet));
    }
    window.localStorage.removeItem(storageKey(suffix));
  }
  clearUnrememberedStoredAdminApiKey(wallet);
  clearLastWalletAddress();
  window.dispatchEvent(new CustomEvent("authChanged"));
}

function clearWalletConnectorStorage() {
  if (typeof window === "undefined") return;
  const shouldRemove = (key: string) => {
    const normalized = key.toLowerCase();
    return (
      normalized.startsWith("wc@") ||
      normalized.startsWith("walletconnect") ||
      normalized.startsWith("@w3m") ||
      normalized.startsWith("@appkit/") ||
      normalized.includes("walletconnect") ||
      normalized.includes("appkit")
    );
  };

  [window.localStorage, window.sessionStorage].forEach(storage => {
    const keysToRemove: string[] = [];
    for (let index = 0; index < storage.length; index += 1) {
      const key = storage.key(index);
      if (key && shouldRemove(key)) keysToRemove.push(key);
    }
    keysToRemove.forEach(key => storage.removeItem(key));
  });
}

export interface PublicSession {
  isLoggedIn: boolean;
  isAmbassadorDistributor: boolean;
  dashboardPath: string;
}

function readStoredProfile(address?: string | null): {
  role?: string;
  brokerId?: string;
} | null {
  if (typeof window === "undefined") return null;
  const wallet = resolveWalletAddress(address);
  const key = wallet
    ? walletStorageKey("orderlyProfile", wallet)
    : storageKey("orderlyProfile");
  const raw = window.localStorage.getItem(key);
  if (!raw) return null;
  try {
    return JSON.parse(raw) as { role?: string; brokerId?: string };
  } catch {
    return null;
  }
}

export function getPublicSession(): PublicSession {
  if (typeof window === "undefined")
    return {
      isLoggedIn: false,
      isAmbassadorDistributor: false,
      dashboardPath: "/home",
    };
  const profile = readStoredProfile();
  const isAmbassadorDistributor =
    profile?.role === "ambassador" || profile?.brokerId === "ambassador";
  const wallet = resolveWalletAddress();
  const hasLoginContext = wallet
    ? !!window.localStorage.getItem(
        walletStorageKey("orderlyLoginContext", wallet)
      )
    : false;
  return {
    isLoggedIn: Boolean(profile || hasLoginContext),
    isAmbassadorDistributor,
    dashboardPath: isAmbassadorDistributor ? "/distributor-dashboard" : "/home",
  };
}

export function setSessionWallet(address: string) {
  setLastWalletAddress(address);
}

export async function disconnectWalletCompletely(
  disconnectAsync?: (variables?: { connector?: Connector }) => Promise<unknown>,
  connections: Array<{ connector?: Connector }> = [],
  address?: string | null
) {
  markWalletIntentionallyDisconnected();
  clearConnectionStorage(address);

  const connectors = connections
    .map(connection => connection.connector)
    .filter(Boolean);
  for (const connector of connectors) {
    try {
      await disconnectAsync?.({ connector });
    } catch {
      // Continue cleanup even if a connector already considers itself disconnected.
    }
  }

  if (connectors.length === 0) {
    try {
      await disconnectAsync?.();
    } catch {
      // Storage cleanup below is the source of truth for preventing reconnect.
    }
  }

  clearWalletConnectorStorage();
  clearConnectionStorage(address);
}
